mapper.update:
UPDATE character_events
   SET balance_after = #{balanceAfter,jdbcType=INTEGER},
       payload       = #{payload,jdbcType=VARCHAR}::jsonb
 WHERE user_id = #{userId}
   AND event_key = #{eventKey}

mapper.select:
UPDATE user_wallets
   SET balance    = balance - #{price},
       updated_at = now()
 WHERE user_id = #{userId}
   AND balance >= #{price}
RETURNING balance

mapper.update:
UPDATE character_events
   SET acked_at = now()
 WHERE user_id = #{userId}
   AND event_key = #{eventKey}
   AND acked_at IS NULL

mapper.select:
SELECT character_code, line_ko, rive_trigger, weight
  FROM character_lines
 WHERE context = #{context}
   AND (character_code = #{characterCode,jdbcType=VARCHAR}
        OR character_code IS NULL)

SELECT id, event_type, coin_delta, balance_after, payload::text AS payload, created_at FROM character_events WHERE user_id = #{userId} AND acked_at IS NULL
AND id < #{cursor}
ORDER BY id DESC LIMIT #{limit}
